import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"玩家常見問題","description":"關於 Fabric 的玩家和伺服器管理員常見問題解答手冊。","frontmatter":{"title":"玩家常見問題","description":"關於 Fabric 的玩家和伺服器管理員常見問題解答手冊。","files":[]},"headers":[],"relativePath":"zh_tw/1.21.10/players/faq.md","filePath":"versions/1.21.10/translated/zh_tw/players/faq.md","lastUpdated":1766682904000}`);var a={name:`zh_tw/1.21.10/players/faq.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">玩家常見問題 <a class="header-anchor" href="#h1" aria-label="Permalink to “玩家常見問題”">​</a></h1><p>有很多問題經常被詢問，所以我們在這裡整理了一個清單。</p><h2 id="what-minecraft-versions-does-fabric-support" tabindex="-1">Fabric 支援哪些 Minecraft 版本？ <a class="header-anchor" href="#what-minecraft-versions-does-fabric-support" aria-label="Permalink to “Fabric 支援哪些 Minecraft 版本？”">​</a></h2><p>官方支援的 Fabric 版本包括從 <code>18w43b</code> 開始的所有快照版本，以及 <code>1.14</code> 及以上的正式版本。</p><h2 id="where-can-i-download-published-fabric-mods" tabindex="-1">我在哪裡可以下載已發布的 Fabric 模組？ <a class="header-anchor" href="#where-can-i-download-published-fabric-mods" aria-label="Permalink to “我在哪裡可以下載已發布的 Fabric 模組？”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>您應該始終檢查模組是否來自可信的來源。 參閱<a href="./finding-mods">尋找可信賴的模組</a>指南以取得更多資訊。</p></div><p>大部分作者會將他們的模組發布到 <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> 和 <a href="https://www.curseforge.com/minecraft/search?class=mc-mods&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a>，但有些人可能選擇將它們上傳到他們的個人網站，或其他平台，例如 GitHub 存儲庫。</p><h2 id="where-can-i-find-premade-fabric-modpacks" tabindex="-1">我在哪裡可以找到預製的 Fabric 模組包？ <a class="header-anchor" href="#where-can-i-find-premade-fabric-modpacks" aria-label="Permalink to “我在哪裡可以找到預製的 Fabric 模組包？”">​</a></h2><p>你可以在各種平台上找到預製的 Fabric 模組包，例如：</p><ul><li><a href="https://modrinth.com/modpacks?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a></li><li><a href="https://www.curseforge.com/minecraft/search?class=modpacks%5C&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a></li><li><a href="https://www.feed-the-beast.com/ftb-app" target="_blank" rel="noreferrer">Feed The Beast</a></li><li><a href="https://www.technicpack.net/modpacks" target="_blank" rel="noreferrer">Technic</a></li></ul>`,10)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};